import os
from flask import Flask, jsonify
from datetime import datetime, timedelta
import pickle
import json
import hashlib

app = Flask(__name__)

# Cache directory and file name
CACHE_DIR = 'cache'
CACHE_FILE = 'data.pkl'

def cache_response(func):
    def wrapper(*args, **kwargs):
        key = hashlib.sha256(json.dumps(args + kwargs).encode()).hexdigest()
        cache_path = os.path.join(CACHE_DIR, f'{key}.json')
        
        # Check if cached response exists
        try:
            with open(cache_path, 'r') as f:
                data = json.load(f)
                return jsonify(data['response'])
        except FileNotFoundError:
            pass
        
        # If not cached, compute the result and store it in cache
        result = func(*args, **kwargs)
        
        # Store response data to disk with metadata (timestamp and expiration time)
        timestamp = datetime.now().strftime('%Y-%m-%d %H:%M:%S')
        expiration_time = (datetime.now() + timedelta(minutes=30)).strftime('%Y-%m-%d %H:%M:%S')
        data = {'response': result, 'metadata': {'timestamp': timestamp, 'expiration_time': expiration_time}}
        
        with open(cache_path, 'w') as f:
            json.dump(data, f)
        
        return jsonify(result)
    
    return wrapper

@app.route('/api/data', methods=['GET'])
@cache_response
def get_data():
    # Simulate expensive API response
    data = {'id': 1, 'name': 'John Doe', 'age': 30}
    return data

if __name__ == '__main__':
    app.run(debug=True)